// --- Product view models ---

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

